  additionalProperties: false,
};

export const componentOptionsSchema = {
  type: 'object',
  properties: {
    items: {
      type: 'array',
      items: {
        type: 'string',
        description: 'A specific variant or option for the component',
      },
      description: 'List of known variants for the component',
    },
  },
  required: ['items'],
  additionalProperties: false,
};

