import callLlm from '../../lib/llm/index.js';
import retry from '../../lib/retry/index.js';
import windowFor from '../../lib/window-for/index.js';

/**
 * Join text fragments using AI with windowed processing for equal context exposure.
 * The prompt dictates all aspects of joining including style, spacing, and format.
 *
 * @param {string[]} list - Array of text fragments to join
 * @param {string} prompt - Instructions for how to join fragments (dictates all style/format)
 * @param {object} config - Configuration options
 * @param {number} config.windowSize - Size of overlapping windows (default: 5)
 * @param {number} config.overlapPercent - Percentage of overlap between windows (default: 50)
 * @param {string} config.styleHint - Optional additional style guidance
 * @param {number} config.maxRetries - Maximum retry attempts (default: 2)
 * @returns {Promise<string>} Single result as dictated by prompt
 */
export default async function join(
  list,
  prompt = 'Join these text fragments into a coherent, unified text. Preserve key information while ensuring smooth transitions between fragments. Remove redundancy and maintain consistent style throughout.',
  config = {}
) {
  if (list.length === 0) return '';
  if (list.length === 1) return list[0];

  const {
    windowSize = config.chunkSize || 5, // Backward compatibility with chunkSize
    overlapPercent = 50,
    styleHint = '',
    maxRetries = 2,
    llm,
    onProgress,
    now = new Date(),
    ...options
  } = config;

  // Create overlapping windows using the windowFor utility
  const windows = windowFor(list, windowSize, overlapPercent);

  // Process each window
  const windowResults = [];

  for (const [windowIndex, window] of windows.entries()) {
    const fragmentList = window.fragments.map((f, idx) => `${idx + 1}. ${f}`).join('\n');

    const instruction = `${prompt}${styleHint ? `\n\nStyle guidance: ${styleHint}` : ''}

Window ${windowIndex + 1} of ${windows.length} - Join these fragments:
${fragmentList}

Important: This is part of a larger sequence. Join these fragments while being mindful that this result will be combined with other processed windows. Add necessary connecting words, prepositions, conjunctions, or other filler text to create a coherent, grammatically correct, and semantically meaningful result. Output only the joined result for this window.`;

    const llmConfig = { modelOptions: { ...llm }, ...options };
    const result = await retry(callLlm, {
      label: `join-window-${windowIndex + 1}`,
      maxRetries,
      onProgress,
      now,
      chainStartTime: now,
      llmPrompt: instruction,
      llmConfig,
      logger: options.logger,
    });

    windowResults.push({
      content: result || window.fragments.join(' '),
      window,
    });
  }

  // Filter valid results
  const validResults = windowResults.filter((r) => r.content && r.content.trim());

  if (validResults.length === 1) {
    return validResults[0].content;
  }

  // Stitch operation: preserve terminals, only process overlapping sections
  let stitchedResult = validResults[0].content;

  for (let i = 1; i < validResults.length; i++) {
    const currentResult = validResults[i];
    const previousWindow = validResults[i - 1].window;
    const currentWindow = currentResult.window;

    // Find the overlapping region based on original fragment indices
    const overlapStart = Math.max(previousWindow.startIndex, currentWindow.startIndex);
    const overlapEnd = Math.min(previousWindow.endIndex, currentWindow.endIndex);

    if (overlapStart <= overlapEnd) {
      // There's an overlap - process only the overlapping section
      const overlapFragments = list.slice(overlapStart, overlapEnd + 1);

      const stitchInstruction = `${prompt}${styleHint ? `\n\nStyle guidance: ${styleHint}` : ''}

Stitch these two sections by resolving their overlapping region:

SECTION A (preserve terminals): ${stitchedResult}

SECTION B (preserve terminals): ${currentResult.content}

OVERLAPPING FRAGMENTS (original): ${overlapFragments.join(' | ')}

The terminal ends of both sections should be preserved. Only resolve the overlapping middle region where these fragments appear: ${overlapFragments.join(
        ', '
      )}

Add necessary connecting words, prepositions, conjunctions, or other filler text to create a coherent, grammatically correct, and semantically meaningful result. Output only the final stitched result with terminals preserved.`;

      const stitchConfig = { modelOptions: { ...llm }, ...options };
      const stitchResult = await retry(callLlm, {
        label: `join-stitch-${i}`,
        maxRetries,
        onProgress,
        now,
        chainStartTime: now,
        llmPrompt: stitchInstruction,
        llmConfig: stitchConfig,
        logger: options.logger,
      });

      stitchedResult = stitchResult || stitchedResult;
    } else {
      // No overlap - simple join
      const joinInstruction = `${prompt}${styleHint ? `\n\nStyle guidance: ${styleHint}` : ''}

Join these two non-overlapping sections:
1. ${stitchedResult}
2. ${currentResult.content}

Add necessary connecting words, prepositions, conjunctions, or other filler text to create a coherent, grammatically correct, and semantically meaningful result. Output only the joined result.`;

      const joinConfig = { modelOptions: { ...llm }, ...options };
      const joinResult = await retry(callLlm, {
        label: `join-nonoverlap-${i}`,
        maxAttempts: maxRetries + 1,
        onProgress,
        now,
        chainStartTime: now,
        llmPrompt: joinInstruction,
        llmConfig: joinConfig,
        logger: options.logger,
      });

      stitchedResult = joinResult || stitchedResult;
    }
  }

  return stitchedResult;
}

import { operationTimeoutMultiplier } from '../../constants/models.js';
import callLlm from '../../lib/llm/index.js';
import retry from '../../lib/retry/index.js';
import {
  asObjectWithSchema as asObjectWithSchemaPrompt,
  generateList as generateListPrompt,
  constants as promptConstants,
} from '../../prompts/index.js';
import modelService from '../../services/llm-model/index.js';
import listResultSchema from './list-result.json' with { type: 'json' };

const { onlyJSON, contentIsTransformationSource, onlyJSONArray } = promptConstants;

/**
 * Create model options for structured outputs
 * @param {string|Object} llm - LLM model name or configuration object
 * @returns {Promise<Object>} Model options for llm
 */
function createModelOptions(llm = 'fastGoodCheap') {
  const responseFormat = {
    type: 'json_schema',
    json_schema: {
      name: 'list_result',
      schema: listResultSchema,
    },
  };

  if (typeof llm === 'string') {
    return {
      modelName: llm,
      response_format: responseFormat,
    };
  } else {
    return {
      ...llm,
      response_format: responseFormat,
    };
  }
}

const outputTransformPrompt = (result, schema) => {
  return `${contentIsTransformationSource} ${result}

${asObjectWithSchemaPrompt(schema)}

${onlyJSON}`;
};

const shouldSkipDefault = ({ result, resultsAll } = {}) => {
  return resultsAll.includes(result);
};

const shouldStopDefault = ({ queryCount, startTime } = {}) => {
  return (
    queryCount > 5 ||
    new Date() - startTime >
      operationTimeoutMultiplier * modelService.getBestPublicModel().requestTimeout
  );
};

export const generateList = async function* generateListGenerator(text, options = {}) {
  const resultsAll = [];
  const resultsAllMap = {};
  let isDone = false;
  const {
    shouldSkip = shouldSkipDefault,
    shouldStop = shouldStopDefault,
    model = 'fastGoodCheap',
    maxAttempts = 3,
    onProgress,
    now = new Date(),
    // eslint-disable-next-line no-unused-vars
    _schema,
    ...passThroughOptions
  } = options;

  const startTime = new Date();
  let queryCount = 0;

  while (!isDone) {
    const listPrompt = generateListPrompt(text, {
      ...options,
      existing: resultsAll,
    });

    let resultsNew = [];
    try {
      const modelOptions = createModelOptions(model);
      // eslint-disable-next-line no-await-in-loop
      const results = await retry(callLlm, {
        label: 'list-generate',
        maxAttempts,
        onProgress,
        now,
        chainStartTime: now,
        llmPrompt: listPrompt,
        llmConfig: {
          modelOptions,
          ...passThroughOptions,
        },
        logger: passThroughOptions.logger,
      });

      const resultArray = results?.items || results;
      resultsNew = Array.isArray(resultArray) ? resultArray.filter(Boolean) : [];
    } catch (error) {
      if (/The operation was aborted/.test(error.message)) {
        // eslint-disable-next-line no-console
        console.error('Generate list [error]: Aborted');
        resultsNew = [];
      } else {
        // eslint-disable-next-line no-console
        console.error(
          `Generate list [error]: ${error.message}`,
          listPrompt.slice(0, 100).replace('\n', '\\n')
        );
        isDone = true;
        break;
      }
    }

    const resultsNewUnique = resultsNew.filter((item) => !(item in resultsAllMap));

    queryCount += 1;

    for (const result of resultsNewUnique) {
      const perResultControlFactors = {
        result,
        resultsAll,
        resultsNew,
        queryCount,
        startTime,
      };

      // eslint-disable-next-line no-await-in-loop
      if (await shouldStop(perResultControlFactors)) {
        isDone = true;
        break;
      }

      // eslint-disable-next-line no-await-in-loop
      if (!(await shouldSkip(perResultControlFactors))) {
        resultsAllMap[result] = true;
        resultsAll.push(result);

        yield result;
      }
    }

    const perQueryControlFactors = {
      result: undefined,
      resultsAll: [],
      resultsNew: [],
      queryCount,
      startTime,
    };

    // eslint-disable-next-line no-await-in-loop
    if (await shouldStop(perQueryControlFactors)) {
      isDone = true;
    }
  }
};

export default async function list(prompt, config = {}) {
  const { llm, schema, maxAttempts = 3, onProgress, now = new Date(), ...options } = config;
  const fullPrompt = `${prompt}\n\n${onlyJSONArray}`;

  const modelOptions = createModelOptions(llm);
  const response = await retry(callLlm, {
    label: 'list-main',
    maxAttempts,
    onProgress,
    now,
    chainStartTime: now,
    llmPrompt: fullPrompt,
    llmConfig: {
      modelOptions,
      ...options,
    },
    logger: options.logger,
  });

  // With structured outputs, response should already be parsed and validated
  const result = typeof response === 'string' ? JSON.parse(response) : response;
  // Extract items from the object structure
  const resultArray = result?.items || result;
  const items = Array.isArray(resultArray) ? resultArray : [];

  // If schema is provided, transform each item to match the schema
  if (schema && items.length > 0) {
    const transformedItems = [];
    for (const item of items) {
      const transformPrompt = outputTransformPrompt(item, schema);
      const transformResponse = await retry(callLlm, {
        label: 'list-transform',
        maxAttempts,
        onProgress,
        llmPrompt: transformPrompt,
        llmConfig: {
          modelOptions: {
            ...llm,
          },
          ...options,
        },
        logger: options.logger,
      });
      try {
        const transformedItem = JSON.parse(transformResponse);
        transformedItems.push(transformedItem);
      } catch {
        transformedItems.push(item);
      }
    }
    return transformedItems;
  }

  return items;
}

