import * as R from 'ramda';
import callLlm from '../../lib/llm/index.js';
import retry from '../../lib/retry/index.js';
import { sort as sortPromptInitial } from '../../prompts/index.js';
import sortSchema from './sort-result.json' with { type: 'json' };
import { emitStart, emitComplete, emitStepProgress } from '../../lib/progress-callback/index.js';

/**
 * Create model options for structured outputs
 * @param {string|Object} llm - LLM model name or configuration object
 * @returns {Object} Model options for llm
 */
function createModelOptions(llm = 'fastGoodCheap') {
  const responseFormat = {
    type: 'json_schema',
    json_schema: {
      name: 'sort_result',
      schema: sortSchema,
    },
  };

  if (typeof llm === 'string') {
    return {
      modelName: llm,
      response_format: responseFormat,
    };
  } else {
    return {
      ...llm,
      response_format: responseFormat,
    };
  }
}

// redeclared so it's clearer how tests can override the sorter
let sortPrompt = sortPromptInitial;

export const defaultSortChunkSize = 10;
export const defaultSortExtremeK = 10;
export const defaultSortIterations = 1;

export const useTestSortPrompt = () => {
  sortPrompt = (options, list) => {
    // For testing, return sorted array directly
    // Sort in descending order (z to a) to match test expectations
    return [...list].sort((a, b) => b.localeCompare(a));
  };
};

const sanitizeList = (list) => {
  return [...new Set(list.filter((item) => item.trim() !== ''))];
};

const sort = async (list, criteria, config = {}) => {
  const {
    chunkSize = defaultSortChunkSize,
    extremeK = defaultSortExtremeK,
    iterations = defaultSortIterations,
    selectBottom = true, // New parameter to control bottom selection
    onProgress = undefined, // Callback: ({top, bottom, processed, total}) => void
    llm,
    maxAttempts = 3,
    now = new Date(),
    ...options
  } = config;

  const items = sanitizeList(list);

  emitStart(onProgress, 'sort', {
    totalItems: items.length,
    chunkSize,
    extremeK,
    iterations,
    criteria,
    now,
    chainStartTime: now,
  });

  // Sort a batch of items with LLM
  const sortBatch = async (batch) => {
    const prompt = sortPrompt({ description: criteria }, batch);

    // Handle test mode where sortPrompt returns the list directly
    if (Array.isArray(prompt)) {
      return prompt;
    }

    const modelOptions = createModelOptions(llm);

    const result = await retry(callLlm, {
      label: 'sort-batch',
      maxAttempts,
      onProgress,
      now,
      chainStartTime: now,
      llmPrompt: prompt,
      llmConfig: {
        modelOptions,
        ...options,
      },
    });

    const resultArray = result?.items || result;
    return Array.isArray(resultArray) ? resultArray.filter(Boolean) : [];
  };

  // Process one complete pass through all items
  // This maintains running global extremes that compete with each chunk
  const extractExtremes = async (itemsToProcess, iterationNumber) => {
    const chunks = R.splitEvery(chunkSize, itemsToProcess);

    // Running global extremes - these represent the best/worst we've seen
    let globalTop = [];
    let globalBottom = [];
    let processedChunks = 0;

    for (const chunk of chunks) {
      emitStepProgress(onProgress, 'sort', 'sorting-chunk', {
        iteration: iterationNumber,
        chunkNumber: processedChunks + 1,
        totalChunks: chunks.length,
        chunkSize: chunk.length,
        now: new Date(),
        chainStartTime: now,
      });
      // Current chunk competes with the global extremes
      const itemsToSort = [...chunk, ...globalTop, ...(selectBottom ? globalBottom : [])];

      // eslint-disable-next-line no-await-in-loop
      let sorted = await sortBatch(itemsToSort);

      // Critical: ensure the sorted output contains exactly the items we sent
      // LLMs can sometimes duplicate or drop items
      const inputSet = new Set(itemsToSort);
      const outputSet = new Set(sorted);

      // If sizes don't match, we have duplicates or missing items
      if (sorted.length !== itemsToSort.length || outputSet.size !== inputSet.size) {
        // Find what's missing from the input
        const missing = itemsToSort.filter((item) => !outputSet.has(item));

        // Keep only items that were in the original input (filter out hallucinated items)
        const dedupedSorted = sorted.filter(
          (item, idx, arr) => inputSet.has(item) && arr.indexOf(item) === idx
        );

        // Add back missing items at the end
        sorted = [...dedupedSorted, ...missing];

        // Final check
        if (sorted.length !== itemsToSort.length && process.env.VERBLETS_DEBUG) {
          console.warn(`Sort mismatch: sent ${itemsToSort.length}, got ${sorted.length}`);
        }
      }

      // Update global extremes with the best K from this sort
      globalTop = sorted.slice(0, Math.min(extremeK, sorted.length));
      if (selectBottom) {
        // Take bottom K items, ensuring no overlap with top
        const availableForBottom = Math.max(0, sorted.length - globalTop.length);
        const bottomSliceSize = Math.min(extremeK, availableForBottom);
        globalBottom = bottomSliceSize > 0 ? sorted.slice(-bottomSliceSize) : [];
      }

      processedChunks++;
    }

    // After seeing all chunks, we have the true global extremes
    return {
      top: globalTop,
      bottom: selectBottom ? globalBottom : [],
      selected: new Set([...globalTop, ...(selectBottom ? globalBottom : [])]),
    };
  };

  // Main algorithm: iteratively extract extremes
  const finalTop = [];
  const finalBottom = [];
  let remaining = items;

  for (let iter = 0; iter < iterations && remaining.length > 0; iter++) {
    emitStepProgress(onProgress, 'sort', 'extracting-extremes', {
      iteration: iter + 1,
      totalIterations: iterations,
      remainingItems: remaining.length,
      now: new Date(),
      chainStartTime: now,
    });

    // eslint-disable-next-line no-await-in-loop
    const { top, bottom, selected } = await extractExtremes(remaining, iter + 1);

    // Accumulate results
    finalTop.push(...top);
    if (selectBottom) {
      // For bottom items, prepend to maintain correct order
      // Items from later iterations are "less bad" than earlier ones
      finalBottom.unshift(...bottom);
    }

    // Remove selected items for next iteration
    remaining = remaining.filter((item) => !selected.has(item));

    // Progress callback after each complete iteration
    if (onProgress) {
      onProgress({
        top: finalTop,
        bottom: finalBottom,
        iteration: iter + 1,
        remaining: remaining.length,
      });
    }
  }

  // Assemble final result, ensuring we return exactly the original items
  // LLMs may slightly modify strings, so reconcile against the original item set
  const assembled = selectBottom
    ? [...finalTop, ...remaining, ...finalBottom]
    : [...finalTop, ...remaining];

  const itemSet = new Set(items);
  const seen = new Set();
  const result = [];

  // First pass: keep items that are in the original set, deduplicating
  for (const item of assembled) {
    if (itemSet.has(item) && !seen.has(item)) {
      seen.add(item);
      result.push(item);
    }
  }

  // Second pass: add any original items that were lost (append at end)
  for (const item of items) {
    if (!seen.has(item)) {
      result.push(item);
    }
  }

  emitComplete(onProgress, 'sort', {
    totalItems: items.length,
    iterations,
    topItems: finalTop.length,
    bottomItems: finalBottom.length,
    remainingItems: remaining.length,
    now: new Date(),
    chainStartTime: now,
  });

  return result;
};

export default async function sortWrapper(list, criteria, config = {}) {
  return await sort(list, criteria, config);
}

import callLlm from '../../lib/llm/index.js';
import retry from '../../lib/retry/index.js';
import chunkSentences from '../../lib/chunk-sentences/index.js';
import wrapVariable from '../../prompts/wrap-variable.js';

// improbable delimiter string, similar to a multipart form boundary
const defaultDelimiter = '---763927459---';

const buildPrompt = (chunk, instructions, delimiter, context = {}) => {
  const { previousContent = '', targetSplitCount = null } = context;

  let prompt = `You are marking split points in text with "${delimiter}". 

${wrapVariable(instructions, { tag: 'instructions', forceHTML: true })}

IMPORTANT RULES:
- Only insert "${delimiter}" at natural break points - do NOT split mid-sentence
- Each section should be substantively different from adjacent sections
- Preserve ALL original text exactly - only add delimiters
- For topic changes: Look for shifts in subject matter, not just related themes
- Be selective - fewer, more meaningful splits are better than many weak ones`;

  if (targetSplitCount) {
    prompt += `\n- Aim for approximately ${targetSplitCount} sections in this chunk`;
  }

  if (previousContent) {
    prompt += `\n\nPREVIOUS CONTEXT (for continuity):\n${previousContent.slice(-200)}...\n`;
  }

  prompt += `\n\n${wrapVariable(chunk, { tag: 'text-to-process', forceHTML: true })}`;

  return prompt;
};

export default async function split(text, instructions, config = {}) {
  const {
    chunkLen = 4000,
    delimiter = defaultDelimiter,
    maxAttempts = 2,
    llm,
    targetSplitsPerChunk = null,
    onProgress,
    now = new Date(),
    ...options
  } = config;

  const chunks = chunkSentences(text, chunkLen);

  // Process chunks in parallel for better performance
  const promises = chunks.map(async (chunk, index) => {
    const context = {
      targetSplitCount: targetSplitsPerChunk,
    };

    const prompt = buildPrompt(chunk, instructions, delimiter, context);
    const llmConfig = {
      modelOptions: {
        temperature: 0.1, // Lower temperature for more consistent splitting
        modelName: 'fastGoodCheapCoding', // Use faster model for better performance
        ...llm,
      },
      ...options,
    };

    try {
      const output = await retry(callLlm, {
        label: 'split',
        maxAttempts,
        onProgress,
        now,
        chainStartTime: now,
        llmPrompt: prompt,
        llmConfig,
        logger: options.logger,
      });

      const outputWithoutDelimiters = output.replace(
        new RegExp(delimiter.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
        ''
      );
      const originalChunk = chunk.trim();

      // If the output is significantly different, fall back to original
      // Be more lenient for shorter texts (common in tests)
      const maxDifference = originalChunk.length < 100 ? 0.5 : 0.1;
      if (
        Math.abs(outputWithoutDelimiters.length - originalChunk.length) >
        originalChunk.length * maxDifference
      ) {
        if (options.logger?.warn) {
          options.logger.warn(
            `Split output differs significantly from input for chunk ${
              index + 1
            }, using original chunk`
          );
        }
        return chunk;
      }

      return output;
    } catch (error) {
      if (options.logger?.warn) {
        options.logger.warn(`Split failed for chunk ${index + 1}:`, error.message);
      }
      return chunk;
    }
  });

  const results = await Promise.all(promises);
  return results.join('');
}

import llm from '../../lib/llm/index.js';
import pave from '../../lib/pave/index.js';
import shortenText from '../../lib/shorten-text/index.js';
import { summarize as basicSummarize, tokenBudget } from '../../prompts/index.js';
import modelService from '../../services/llm-model/index.js';

const summarize = ({ budget, type, value, fixes = [], modelOptions, privacy }) => {
  if (budget) {
    fixes.push(tokenBudget(budget));
  }

  if (type === 'code') {
    fixes.push('Output function signature lines and a closing bracket.');
    fixes.push(
      'Comment out the bodies of the functions and leave a summary of the implementation.'
    );
    fixes.push('Remove the function header if it exists.');
  }

  if (privacy?.whitelist) {
    fixes.push(`Only share information matching: ${privacy.whitelist}.`);
  }

  if (privacy?.blacklist) {
    fixes.push(`Do not share information matching: ${privacy.blacklist}.`);
  }

  const fixesAsBullets = fixes.map((fix) => ` - ${fix}`);

  return llm(basicSummarize(value, `${fixesAsBullets.join('\n')}`), {
    modelOptions,
  });
};

/**
 * SummaryMap is a utility class for automatically summarizing prompt inputs
 *   to fit within a desired desired token budget.
 */
export default class SummaryMap extends Map {
  constructor({
    maxTokensPerValue,
    model = modelService.getBestPublicModel(),
    modelOptions = { modelName: model.name },
    promptText,
    targetTokens,
    // used with promptText, when targetTokens isn't supplied
    targetTokensTotalRatio = 0.3,
  }) {
    super();
    this.cache = new Map();
    this.data = new Map();
    this.isCacheValid = false;
    this.maxTokensPerValue = maxTokensPerValue ?? model.maxTokens;
    this.modelOptions = { modelName: model.name, ...modelOptions };

    if (targetTokens) {
      this.targetTokens = targetTokens;
    } else if (promptText && model) {
      this.promptTokens = model.toTokens(promptText).length;
      const maxModelTokens = model.maxTokens;
      const remainingTokens = maxModelTokens - this.promptTokens;
      this.targetTokens = Math.floor(remainingTokens - remainingTokens * targetTokensTotalRatio);
    } else {
      throw new Error('Either "promptText" and "model" or "targetTokens" must be provided.');
    }
  }

  calculateBudgets() {
    const totalSizeWeight = [...this.data.values()]
      .filter((obj) => obj?.summary !== false)
      .reduce((sum, valueObject) => {
        return sum + (valueObject.weight ?? 1) * valueObject.value.length;
      }, 0);
    const sortedEntries = [...this.data.entries()].sort((a, b) => a[1].weight - b[1].weight);

    const budgets = [];
    for (const [entryKey, valueObject] of sortedEntries) {
      const sizeWeight = valueObject.value.length * (valueObject.weight ?? 1);
      const budget = Math.floor((sizeWeight / totalSizeWeight) * this.targetTokens);

      if (valueObject.weight) {
        budgets.push({ key: entryKey, budget });
      } else {
        budgets.push({ key: entryKey });
      }
    }

    return { totalSizeWeight, budgets };
  }

  async myFillCache() {
    const { budgets } = this.calculateBudgets();

    for (const { key, budget } of budgets) {
      const valueObject = this.data.get(key);

      const entryModelOptions = {
        ...this.modelOptions,
        ...valueObject.modelOptions,
      };

      if (valueObject.privacy?.whitelist || valueObject.privacy?.blacklist) {
        entryModelOptions.modelName = 'privacy';
      }

      const value = shortenText(valueObject.value, {
        targetTokenCount: this.maxTokensPerValue,
        model: modelService.getModel(entryModelOptions.modelName),
      });

      // omit weight to skip summarization
      let summarizedValue = value;
      if (budget) {
        const summarizeModelOptions = {
          ...this.modelOptions,
          ...valueObject.modelOptions,
        };

        if (valueObject.privacy?.whitelist || valueObject.privacy?.blacklist) {
          summarizeModelOptions.modelName = 'privacy';
        }

        // eslint-disable-next-line no-await-in-loop
        summarizedValue = await summarize({
          budget,
          fixes: valueObject.fixes,
          modelOptions: summarizeModelOptions,
          privacy: valueObject.privacy,
          type: valueObject.type,
          value,
        });
      }

      this.cache.set(key, summarizedValue);
    }

    this.isCacheValid = true;
  }

  getCache() {
    return this.cache;
  }

  set(key, config) {
    this.data.set(key, config);
    this.cache.delete(key);
    this.isCacheValid = false;
  }

  delete(key) {
    this.data.delete(key);
    this.cache.delete(key);
    this.isCacheValid = false;
  }

  clear() {
    this.data.clear();
    this.cache.clear();
    this.isCacheValid = false;
  }

  getStale(key) {
    return this.cache.get(key);
  }

  get(key) {
    if (!super.has(key)) {
      return null;
    }

    if (!this.isCacheValid) {
      return this.myFillCache()
        .then(() => this.cache.get(key))
        .catch((error) => {
          return Promise.reject(error);
        });
    }

    return Promise.resolve(this.getStale(key));
  }

  valuesStale() {
    return this.cache.values();
  }

  values() {
    if (!this.isCacheValid) {
      return this.myFillCache()
        .then(() => this.cache.values())
        .catch((error) => {
          return Promise.reject(error);
        });
    }
    return Promise.resolve(this.valuesStale());
  }

  entriesStale() {
    return this.cache.entries();
  }

  entries() {
    if (!this.isCacheValid) {
      return this.myFillCache()
        .then(() => this.cache.entries())
        .catch((error) => {
          return Promise.reject(error);
        });
    }
    return Promise.resolve(this.entriesStale());
  }

  pavedSummaryResultStale() {
    return Array.from(this.entriesStale()).reduce((acc, [k, v]) => pave(acc, k, v), {});
  }

  pavedSummaryResult() {
    if (!this.isCacheValid) {
      return this.myFillCache()
        .then(() => this.pavedSummaryResultStale())
        .catch((error) => {
          return Promise.reject(error);
        });
    }
    return Promise.resolve(this.pavedSummaryResultStale());
  }
}

