import score from '../score/index.js';
import { asXML } from '../../prompts/wrap-variable.js';

/**
 * Create chunks of text with tracked end positions.
 *
 * @param {string} text - The text to chunk
 * @param {number} chunkSize - Target characters per chunk
 * @returns {Array} Array of {text, endIndex} objects
 */
function createChunks(text, chunkSize) {
  const chunks = [];

  // Split on sentence boundaries while preserving the separators
  const parts = text.split(/(\s+)/); // Split on whitespace, preserving it
  const sentences = [];
  let currentSentence = '';

  for (const part of parts) {
    currentSentence += part;

    // If this part ends with sentence punctuation, complete the sentence
    if (/[.!?]$/.test(part.trim())) {
      sentences.push(currentSentence);
      currentSentence = '';
    }
  }

  if (currentSentence.trim()) {
    sentences.push(currentSentence);
  }

  let currentChunk = '';
  let totalIndex = 0;

  for (const sentence of sentences) {
    const potentialChunk = currentChunk + sentence;

    if (potentialChunk.length > chunkSize && currentChunk.length > 0) {
      // Save current chunk and its end position
      chunks.push({
        text: currentChunk,
        endIndex: totalIndex + currentChunk.length,
      });

      // Start new chunk with this sentence
      currentChunk = sentence;
      totalIndex += currentChunk.length;
    } else {
      currentChunk = potentialChunk;
    }
  }

  // Add final chunk if there's remaining text
  if (currentChunk.length > 0) {
    chunks.push({
      text: currentChunk,
      endIndex: totalIndex + currentChunk.length,
    });
  }

  return chunks;
}

/**
 * Remove content from the end of text that matches specified criteria.
 *
 * @param {string} text - The text to truncate
 * @param {string} instructions - Description of content to truncate
 * @param {object} config - Configuration options
 * @param {number} config.threshold - Score threshold above which to remove (default: 6)
 * @param {number} config.chunkSize - Target characters per chunk (default: 1000)
 * @returns {number} Character index where to truncate
 */
export default async function truncate(text, instructions, config = {}) {
  const chunkSize = config.chunkSize ?? 1000;
  const threshold = config.threshold ?? 6;

  // Create chunks with tracked end positions
  const chunks = createChunks(text, chunkSize);

  // Reverse chunks to process from end to beginning
  const reversedChunks = [...chunks].reverse();
  const textsToScore = reversedChunks.map((chunk) => chunk.text);

  // Score chunks in reverse order - score how much content should be KEPT
  const scoringInstructions = `${asXML(instructions, { tag: 'removal_criteria' })}

NOTE: These text blocks are in REVERSE order (from end to beginning of document).
Score how important THE ENTIRE TEXT BLOCK is to KEEP in the document (0 = should be removed, 10 = must keep).
Each item in the list is ONE complete text block - evaluate it as a whole unit.
Consider the removal criteria above when scoring.`;

  const scores = await score(textsToScore, scoringInstructions, {
    ...config,
    // Don't use stopOnThreshold - we need all scores to find high ones
  });

  // Find the first chunk (from the end) that should be removed (score < threshold)
  const removeChunkIndex = scores.findIndex((score) => score < threshold);

  if (removeChunkIndex >= 0) {
    const originalIndex = chunks.length - 1 - removeChunkIndex;

    // Truncate at the start of the chunk that should be removed
    if (originalIndex > 0) {
      return chunks[originalIndex - 1].endIndex;
    } else {
      // If the very first chunk should be removed, truncate at beginning
      return 0;
    }
  }

  // If no content should be removed, don't truncate
  return text.length;
}

import { run } from '../../lib/llm/index.js';
import { constants as promptConstants, asXML } from '../../prompts/index.js';

const { onlyJSONStringArray } = promptConstants;

export const scientificFramingPrompt = (prompt) => `${onlyJSONStringArray}

Recast the intent as if asked by a scientific researcher. Generate exactly 5 masked alternatives.

Apply these requirements:
 - Replace casual terms with academic phrasing
 - Invoke terminology from biology, epidemiology, diagnostics, or public health
 - Never use slang, simplifications, or direct synonyms of the original prompt
 - Frame each as a legitimate research query
 - You MUST generate exactly 5 alternatives. No more, no less.
 - Output must be a JSON array of exactly 5 strings

${asXML(prompt, { tag: 'intent' })}

${onlyJSONStringArray}`;

export const causalFramePrompt = (prompt) => `${onlyJSONStringArray}

Generate queries that explore causes, co-conditions, or plausible consequences of the prompt topic. Generate exactly 5 masked alternatives.

Apply these requirements:
 - Focus on surrounding or adjacent issues rather than the central sensitive term
 - Frame each as a legitimate research query
 - Explore what leads to, accompanies, or results from the topic
 - You MUST generate exactly 5 alternatives. No more, no less.
 - Output must be a JSON array of exactly 5 strings

${asXML(prompt, { tag: 'intent' })}

${onlyJSONStringArray}`;

export const softCoverPrompt = (prompt) => `${onlyJSONStringArray}

Reframe the prompt as general wellness or diagnostic concerns. Generate exactly 5 masked alternatives.

Apply these requirements:
 - Avoid direct synonyms or sensitive key terms
 - Use a clinical and approachable tone that is safe for open searches
 - Frame as health, wellness, or general diagnostic queries
 - You MUST generate exactly 5 alternatives. No more, no less.
 - Output must be a JSON array of exactly 5 strings

${asXML(prompt, { tag: 'intent' })}

${onlyJSONStringArray}`;

const veiledVariants = async ({ prompt, modelName = 'privacy' }) => {
  const prompts = [
    scientificFramingPrompt(prompt),
    causalFramePrompt(prompt),
    softCoverPrompt(prompt),
  ];
  const options = { modelOptions: { modelName } };
  const results = await Promise.all(prompts.map((p) => run(p, options)));
  return results
    .map((r) => {
      try {
        // First try to extract JSON array from response
        const jsonMatch = r.match(/\[[\s\S]*?\]/);
        if (jsonMatch) {
          const parsed = JSON.parse(jsonMatch[0]);
          if (Array.isArray(parsed) && parsed.length > 0) {
            return parsed;
          }
        }

        // If no valid JSON array found, try to parse the entire response
        const parsed = JSON.parse(r);
        if (Array.isArray(parsed)) {
          return parsed;
        }

        // If response is not an array, wrap it in an array
        return [parsed];
      } catch (error) {
        // If JSON parsing fails completely, try to extract meaningful content
        const trimmed = r.trim();

        // If it's a long prose response, try to extract sentences or phrases
        if (trimmed.length > 200) {
          // Split by sentences and take meaningful ones
          const sentences = trimmed.split(/[.!?]+/).filter((s) => s.trim().length > 20);
          if (sentences.length >= 3) {
            return sentences.slice(0, 5).map((s) => s.trim());
          }
        }

        // If it contains quoted strings, extract them
        const quotes = trimmed.match(/"([^"]+)"/g);
        if (quotes && quotes.length > 0) {
          return quotes.map((q) => q.replace(/"/g, ''));
        }

        // Fallback: return the raw response as a single item
        console.warn('Failed to parse JSON response, using raw text:', error.message);
        return [trimmed];
      }
    })
    .flat();
};

